  ('elementary-c5fb3965-moex-00185', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '下列何項情形，於審判中未經選任辯護人者，審判長應指定公設辯護人或律師為被告辯護？', '["被告犯內亂罪", "被告犯醉態駕駛罪", "被告犯侵占遺失物罪", "被告犯公然侮辱罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00186', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '下列何項事實，應經舉證證明？', '["台積電是股票上市公司之事實", "法官職務上所已知之事實", "臺灣地區之日出、日沒時刻", "被告抗辯自白不具任意性之事實"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00187', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '被告及其辯護人於偵查中之羈押審查程序，有關權利與限制規定，下列敘述何者正確？', '["基於偵查不公開原則，在偵查中之羈押審查程序，檢察官得限制被告與其辯護人接見", "基於偵查不公開原則，在偵查中之羈押審查程序，檢察官得限制被告與其辯護人通訊", "被告及其辯護人得於法官訊問前，請求給予適當時間為答辯之準備", "被告得請求檢閱所有檢察官送交法院之卷宗及證物並得抄錄、重製或攝影"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00188', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '刑法第14條第1項規定「行為人雖非故意，但按其情節應注意，並能注意，而不注意者，為過失。」下 列何者不屬於本項注意義務的來源？', '["法令規則", "業界成規", "契約", "法律草案"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL),
  ('elementary-c5fb3965-moex-00189', 'elementary-c5fb3965', 'elementary-c5fb3965-moex-114-55d283b0', 'sub-elementary-c5fb3965-04', NULL, 'single_choice', '關於正當防衛，下列敘述何者錯誤？', '["防衛過當，僅能減輕或免除其刑，不能阻卻違法", "正當防衛之所以不罰，是因為阻卻行為之違法性", "正當防衛必須對於現時不法之侵害，出於防衛自己或他人權利之行為", "正當防衛行為之所以不罰，是因行為人無責任能力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:06+00:00", "source_pdf_sha1": "4650d08b9bf7", "answer_pdf_sha1": "316348d8632d", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "503", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "戶政"}'::jsonb, NULL)
